import React, { useEffect, useState } from 'react';

function App() {
  const [campuses, setCampuses] = useState([]);
  const [selectedCampus, setSelectedCampus] = useState(null);
  const [drops, setDrops] = useState([]);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetch('/api/campuses/')
      .then((r) => r.json())
      .then((data) => setCampuses(data))
      .catch((err) => setError('Failed to load campuses'));
  }, []);

  useEffect(() => {
    if (!selectedCampus) return;
    fetch(`/api/drops/?campus=${selectedCampus.slug}`)
      .then((r) => r.json())
      .then((data) => setDrops(data))
      .catch((err) => setError('Failed to load drops'));
  }, [selectedCampus]);

  return (
    <div style={{ padding: '1rem' }}>
      <h1>ccoop.in MVP</h1>
      {error && <div style={{ color: 'red' }}>{error}</div>}
      <h2>Campuses</h2>
      <ul>
        {campuses.map((c) => (
          <li key={c.id}>
            <button onClick={() => setSelectedCampus(c)}>{c.name}</button>
          </li>
        ))}
      </ul>
      {selectedCampus && (
        <>
          <h2>Drops for {selectedCampus.name}</h2>
          <ul>
            {drops.map((d) => (
              <li key={d.id}>{d.title}</li>
            ))}
          </ul>
        </>
      )}
    </div>
  );
}

export default App;
